#!/bin/bash
# RootSpoofer v2.0 - Patch any APK to spoof root environment
# Usage: bash patch_apk.sh <target.apk> [--install]
#        bash patch_apk.sh --download <package_name> [--install]

set -e

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'; BLUE='\033[0;34m'; NC='\033[0m'
ROOT_DIR="$HOME/rootspoofer"
WORK_DIR="$ROOT_DIR/work_$(date +%s)"
OUTPUT_DIR="$ROOT_DIR/output"
ROOTFS="$ROOT_DIR/rootfs"
GADGETS="$ROOT_DIR/gadgets"
BYPASS_JS="$ROOT_DIR/bypass_root.js"
FRIDA_CONFIG="$ROOT_DIR/frida-gadget.config.json"

mkdir -p "$WORK_DIR" "$OUTPUT_DIR" "$GADGETS"
export PATH="$ROOT_DIR/bin:$PATH"

# Colors for output
log() { echo -e "${GREEN}[+]${NC} $1"; }
warn() { echo -e "${YELLOW}[!]${NC} $1"; }
err() { echo -e "${RED}[X]${NC} $1"; exit 1; }
info() { echo -e "${BLUE}[*]${NC} $1"; }

# Usage
if [ $# -eq 0 ]; then
    echo "RootSpoofer v2.0 - Complete Root Environment Emulator"
        echo ""
            echo "Usage:"
                echo "  bash $0 <target.apk>             Patch an APK file"
                    echo "  bash $0 --download <pkg>         Download + patch from device"
                        echo "  bash $0 --install <apk>          Patch and auto-install"
                            echo "  bash $0 --download-install <pkg> Download, patch, install"
                                echo ""
                                    echo "Options:"
                                        echo "  --frida-off          Don't inject Frida gadget"
                                            echo "  --no-sign            Don't sign the APK"
                                                echo "  --output <path>      Custom output path"
                                                    exit 0
                                                    fi

                                                    # Parse arguments
                                                    AUTO_INSTALL=false
                                                    DOWNL=false
                                                    INJECT_FRIDA=true
                                                    DO_SIGN=true
                                                    TARGET=""

                                                    while [ $# -gt 0 ]; do
                                                        case "$1" in
                                                                --download) DOWNL=true; TARGET="$2"; shift 2 ;;
                                                                        --download-install) DOWNL=true; AUTO_INSTALL=true; TARGET="$2"; shift 2 ;;
                                                                                --install) AUTO_INSTALL=true; TARGET="$2"; shift 2 ;;
                                                                                        --frida-off) INJECT_FRIDA=false; shift ;;
                                                                                                --no-sign) DO_SIGN=false; shift ;;
                                                                                                        --output) OUTPUT_DIR="$2"; shift 2 ;;
                                                                                                                *) TARGET="$1"; shift ;;
                                                                                                                    esac
                                                                                                                    done

                                                                                                                    # Download from device if needed
                                                                                                                    if [ "$DOWNL" = true ]; then
                                                                                                                        info "Downloading $TARGET from device..."
                                                                                                                            APK_PATH=$(adb shell pm path "$TARGET" 2>/dev/null | head -1 | sed 's/package://')
                                                                                                                                [ -z "$APK_PATH" ] && err "Package $TARGET not found on device"
                                                                                                                                    adb pull "$APK_PATH" "$OUTPUT_DIR/${TARGET}.apk" || err "Failed to pull APK"
                                                                                                                                        TARGET="$OUTPUT_DIR/${TARGET}.apk"
                                                                                                                                            log "Downloaded: $TARGET"
                                                                                                                                            fi

                                                                                                                                            [ ! -f "$TARGET" ] && err "APK not found: $TARGET"

                                                                                                                                            TARGET_NAME=$(basename "$TARGET" .apk)
                                                                                                                                            OUTPUT_APK="$OUTPUT_DIR/${TARGET_NAME}_rootspoofed.apk"

                                                                                                                                            log "Target: $TARGET"
                                                                                                                                            log "Output: $OUTPUT_APK"

                                                                                                                                            # Step 1: Decompile
                                                                                                                                            info "[1/8] Decompiling APK..."
                                                                                                                                            java -jar "$ROOT_DIR/apktool.jar" d -f -o "$WORK_DIR/decompiled" "$TARGET" || err "Decompile failed"
                                                                                                                                            log "Decompiled successfully"

                                                                                                                                            # Step 2: Detect architecture
                                                                                                                                            info "[2/8] Detecting architecture..."
                                                                                                                                            ARCH=""
                                                                                                                                            for dir in arm64-v8a armeabi-v7a x86_64 x86; do
                                                                                                                                                if [ -d "$WORK_DIR/decompiled/lib/$dir" ]; then
                                                                                                                                                        ARCH="$dir"
                                                                                                                                                                log "Architecture: $ARCH"
                                                                                                                                                                        break
                                                                                                                                                                            fi
                                                                                                                                                                            done
                                                                                                                                                                            [ -z "$ARCH" ] && { ARCH="arm64-v8a"; mkdir -p "$WORK_DIR/decompiled/lib/$ARCH"; warn "No lib dir found, using $ARCH"; }

                                                                                                                                                                            # Map arch to frida name
                                                                                                                                                                            case "$ARCH" in
                                                                                                                                                                                arm64-v8a) FRIDA_ARCH="arm64" ;;
                                                                                                                                                                                    armeabi-v7a) FRIDA_ARCH="arm" ;;
                                                                                                                                                                                        x86_64) FRIDA_ARCH="x86_64" ;;
                                                                                                                                                                                            x86) FRIDA_ARCH="x86" ;;
                                                                                                                                                                                                *) FRIDA_ARCH="arm64" ;;
                                                                                                                                                                                                esac

                                                                                                                                                                                                # Step 3: Inject Frida gadget
                                                                                                                                                                                                if [ "$INJECT_FRIDA" = true ]; then
                                                                                                                                                                                                    info "[3/8] Injecting Frida gadget..."
                                                                                                                                                                                                        GADGET_FILE="$GADGETS/frida-gadget-$FRIDA_ARCH.so"
                                                                                                                                                                                                            
                                                                                                                                                                                                                if [ ! -f "$GADGET_FILE" ]; then
                                                                                                                                                                                                                        warn "Downloading Frida gadget for $FRIDA_ARCH..."
                                                                                                                                                                                                                                FRIDA_VERSION="16.2.1"
                                                                                                                                                                                                                                        wget -q "https://github.com/frida/frida/releases/download/${FRIDA_VERSION}/frida-gadget-${FRIDA_VERSION}-android-${FRIDA_ARCH}.so.xz" -O "$GADGET_FILE.xz"
                                                                                                                                                                                                                                                xz -d "$GADGET_FILE.xz" || err "Failed to download Frida gadget"
                                                                                                                                                                                                                                                    fi
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                            for dir in "$WORK_DIR/decompiled/lib"/*/; do
                                                                                                                                                                                                                                                                    cp "$GADGET_FILE" "${dir}libfrida-gadget.so"
                                                                                                                                                                                                                                                                            log "Injected gadget into: $dir"
                                                                                                                                                                                                                                                                                done
                                                                                                                                                                                                                                                                                fi

                                                                                                                                                                                                                                                                                # Step 4: Inject fake root filesystem
                                                                                                                                                                                                                                                                                info "[4/8] Injecting fake root filesystem..."
                                                                                                                                                                                                                                                                                ASSETS_DIR="$WORK_DIR/decompiled/assets"
                                                                                                                                                                                                                                                                                mkdir -p "$ASSETS_DIR/rootfs"

                                                                                                                                                                                                                                                                                # Create fake su binary (static)
                                                                                                                                                                                                                                                                                cat > "$ASSETS_DIR/rootfs/system/xbin/su" << 'SUEOF'
                                                                                                                                                                                                                                                                                #!/system/bin/sh
                                                                                                                                                                                                                                                                                # Fake su - always returns root
                                                                                                                                                                                                                                                                                echo "uid=0(root) gid=0(root) groups=0(root) context=u:r:su:s0"
                                                                                                                                                                                                                                                                                if [ "$1" = "-c" ] && [ -n "$2" ]; then
                                                                                                                                                                                                                                                                                    eval "$2"
                                                                                                                                                                                                                                                                                    fi
                                                                                                                                                                                                                                                                                    exit 0
                                                                                                                                                                                                                                                                                    SUEOF
                                                                                                                                                                                                                                                                                    chmod 6755 "$ASSETS_DIR/rootfs/system/xbin/su"

                                                                                                                                                                                                                                                                                    # Create fake magisk binary
                                                                                                                                                                                                                                                                                    cat > "$ASSETS_DIR/rootfs/system/bin/magisk" << 'MAGEOF'
                                                                                                                                                                                                                                                                                    #!/system/bin/sh
                                                                                                                                                                                                                                                                                    echo "Magisk v28.0 (RootSpoofer)"
                                                                                                                                                                                                                                                                                    echo "Running in root mode"
                                                                                                                                                                                                                                                                                    exit 0
                                                                                                                                                                                                                                                                                    MAGEOF
                                                                                                                                                                                                                                                                                    chmod 755 "$ASSETS_DIR/rootfs/system/bin/magisk"

                                                                                                                                                                                                                                                                                    # Create fake magiskpolicy
                                                                                                                                                                                                                                                                                    cat > "$ASSETS_DIR/rootfs/system/bin/magiskpolicy" << 'MAGPEOF'
                                                                                                                                                                                                                                                                                    #!/system/bin/sh
                                                                                                                                                                                                                                                                                    echo "MagiskPolicy: Allowed"
                                                                                                                                                                                                                                                                                    exit 0
                                                                                                                                                                                                                                                                                    MAGPEOF
                                                                                                                                                                                                                                                                                    chmod 755 "$ASSETS_DIR/rootfs/system/bin/magiskpolicy"

                                                                                                                                                                                                                                                                                    # Create fake busybox
                                                                                                                                                                                                                                                                                    cat > "$ASSETS_DIR/rootfs/system/xbin/busybox" << 'BBEOF'
                                                                                                                                                                                                                                                                                    #!/system/bin/sh
                                                                                                                                                                                                                                                                                    echo "BusyBox v1.36.1 (RootSpoofer) multi-call binary"
                                                                                                                                                                                                                                                                                    echo "Usage: busybox [applet] [arguments...]"
                                                                                                                                                                                                                                                                                    echo "Applets: cat, chmod, chown, cp, dd, df, echo, grep, gunzip, gzip,"
                                                                                                                                                                                                                                                                                    echo "         kill, ln, ls, mkdir, mount, mv, ps, rm, sed, sh, sleep,"
                                                                                                                                                                                                                                                                                    echo "         tar, touch, umount, uname, which"
                                                                                                                                                                                                                                                                                    BBEOF
                                                                                                                                                                                                                                                                                    chmod 755 "$ASSETS_DIR/rootfs/system/xbin/busybox"

                                                                                                                                                                                                                                                                                    # Create busybox applet symlinks
                                                                                                                                                                                                                                                                                    for applet in cat chmod chown cp dd df echo grep gunzip gzip kill ln ls mkdir mount mv ps rm sed sh sleep tar touch umount uname which; do
                                                                                                                                                                                                                                                                                        ln -sf busybox "$ASSETS_DIR/rootfs/system/xbin/$applet" 2>/dev/null || true
                                                                                                                                                                                                                                                                                        done

                                                                                                                                                                                                                                                                                        # Create Magisk structure
                                                                                                                                                                                                                                                                                        mkdir -p "$ASSETS_DIR/rootfs/data/adb/magisk"
                                                                                                                                                                                                                                                                                        cat > "$ASSETS_DIR/rootfs/data/adb/magisk/config.sh" << 'MAGC'
                                                                                                                                                                                                                                                                                        MAGISK_VER=28.0
                                                                                                                                                                                                                                                                                        MAGISK_VER_CODE=28000
                                                                                                                                                                                                                                                                                        BOOTMODE=true
                                                                                                                                                                                                                                                                                        MOUNTPOINT=/sbin
                                                                                                                                                                                                                                                                                        MAGC

                                                                                                                                                                                                                                                                                        # Create su in /sbin
                                                                                                                                                                                                                                                                                        mkdir -p "$ASSETS_DIR/rootfs/sbin"
                                                                                                                                                                                                                                                                                        cp "$ASSETS_DIR/rootfs/system/xbin/su" "$ASSETS_DIR/rootfs/sbin/su"

                                                                                                                                                                                                                                                                                        # Create SuperSU paths
                                                                                                                                                                                                                                                                                        mkdir -p "$ASSETS_DIR/rootfs/data/data/eu.chainfire.supersu"
                                                                                                                                                                                                                                                                                        mkdir -p "$ASSETS_DIR/rootfs/data/data/com.noshufou.android.su"
                                                                                                                                                                                                                                                                                        mkdir -p "$ASSETS_DIR/rootfs/data/data/com.topjohnwu.magisk"

                                                                                                                                                                                                                                                                                        # Create /system/app stubs
                                                                                                                                                                                                                                                                                        touch "$ASSETS_DIR/rootfs/system/app/Superuser.apk"
                                                                                                                                                                                                                                                                                        touch "$ASSETS_DIR/rootfs/system/app/MagiskManager.apk"

                                                                                                                                                                                                                                                                                        # Create init.d
                                                                                                                                                                                                                                                                                        cat > "$ASSETS_DIR/rootfs/system/etc/init.d/99SuperSUDaemon" << 'INITD'
                                                                                                                                                                                                                                                                                        #!/system/bin/sh
                                                                                                                                                                                                                                                                                        # Root daemon placeholder
                                                                                                                                                                                                                                                                                        INITD
                                                                                                                                                                                                                                                                                        chmod 755 "$ASSETS_DIR/rootfs/system/etc/init.d/99SuperSUDaemon"

                                                                                                                                                                                                                                                                                        # Create build.prop
                                                                                                                                                                                                                                                                                        cat > "$ASSETS_DIR/rootfs/system/build.prop" << 'BUILD'
                                                                                                                                                                                                                                                                                        ro.build.tags=test-keys
                                                                                                                                                                                                                                                                                        ro.debuggable=1
                                                                                                                                                                                                                                                                                        ro.secure=0
                                                                                                                                                                                                                                                                                        ro.adb.secure=0
                                                                                                                                                                                                                                                                                        persist.sys.root_access=3
                                                                                                                                                                                                                                                                                        ro.kernel.android.checkjni=0
                                                                                                                                                                                                                                                                                        ro.config.nocheckin=1
                                                                                                                                                                                                                                                                                        ro.build.selinux=0
                                                                                                                                                                                                                                                                                        ro.build.type=userdebug
                                                                                                                                                                                                                                                                                        BUILD

                                                                                                                                                                                                                                                                                        # SELinux files
                                                                                                                                                                                                                                                                                        echo "0" > "$ASSETS_DIR/rootfs/selinux/enforce"
                                                                                                                                                                                                                                                                                        echo "Permissive" > "$ASSETS_DIR/rootfs/selinux/policy"

                                                                                                                                                                                                                                                                                        log "Fake root filesystem created"

                                                                                                                                                                                                                                                                                        # Step 5: Copy bypass_root.js
                                                                                                                                                                                                                                                                                        info "[5/8] Copying bypass script..."
                                                                                                                                                                                                                                                                                        cp "$BYPASS_JS" "$ASSETS_DIR/bypass_root.js" 2>/dev/null || {
                                                                                                                                                                                                                                                                                            warn "bypass_root.js not found, using default..."
                                                                                                                                                                                                                                                                                                cat > "$ASSETS_DIR/bypass_root.js" << 'JSDEFAULT'
                                                                                                                                                                                                                                                                                                'use strict';
                                                                                                                                                                                                                                                                                                Java.perform(function() {
                                                                                                                                                                                                                                                                                                    console.log("[RootSpoofer] Bypass loaded");
                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                            // Hook access()
                                                                                                                                                                                                                                                                                                                var accessPtr = Module.findExportByName(null, "access");
                                                                                                                                                                                                                                                                                                                    if(accessPtr) {
                                                                                                                                                                                                                                                                                                                            Interceptor.attach(accessPtr, {
                                                                                                                                                                                                                                                                                                                                        onEnter: function(args) { this.path = Memory.readUtf8String(args[0]); },
                                                                                                                                                                                                                                                                                                                                                    onLeave: function(retval) {
                                                                                                                                                                                                                                                                                                                                                                    if(this.path) {
                                                                                                                                                                                                                                                                                                                                                                                        var lower = this.path.toLowerCase();
                                                                                                                                                                                                                                                                                                                                                                                                            if(lower.indexOf("/su")>=0||lower.indexOf("magisk")>=0||lower.indexOf("superuser")>=0||lower.indexOf("busybox")>=0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                    retval.replace(0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Hook stat()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            var statPtr = Module.findExportByName(null, "stat");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if(statPtr) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Interceptor.attach(statPtr, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onEnter: function(args) { this.path = Memory.readUtf8String(args[0]); },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onLeave: function(retval) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if(this.path) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    var lower = this.path.toLowerCase();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if(lower.indexOf("/su")>=0||lower.indexOf("magisk")>=0) retval.replace(0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Hook Runtime.exec
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            var Runtime = Java.use('java.lang.Runtime');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Runtime.exec.overload('[Ljava.lang.String;').implementation = function(arr) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        var cmd = arr.join(" ");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if(cmd.indexOf("su")>=0||cmd.indexOf("id")>=0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return Java.use('java.lang.ProcessBuilder').$new(['/system/bin/sh','-c','echo "uid=0(root) gid=0(root) groups=0(root)"']).start();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return this.exec(arr);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Runtime.exec.overload('java.lang.String').implementation = function(cmd) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(cmd.indexOf("su")>=0||cmd.indexOf("id")>=0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return Java.use('java.lang.ProcessBuilder').$new(['/system/bin/sh','-c','echo "uid=0(root) gid=0(root) groups=0(root)"']).start();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return this.exec(cmd);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Hook ProcessBuilder
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        var PB = Java.use('java.lang.ProcessBuilder');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            PB.start.implementation = function() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    var cmd = this.command().toString();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(cmd.indexOf("su")>=0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return Java.use('java.lang.ProcessBuilder').$new(['/system/bin/sh','-c','echo "uid=0(root) gid=0(root)"']).start();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return this.start();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Hook File.exists
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        var File = Java.use('java.io.File');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            File.exists.implementation = function() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    var p = this.getAbsolutePath().toLowerCase();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(p.indexOf("su")>=0||p.indexOf("magisk")>=0||p.indexOf("superuser")>=0) return true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return this.exists();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Hook Build
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    var Build = Java.use('android.os.Build');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Build.getTags.implementation = function() { return "test-keys"; };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Hook SystemProperties
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            var SP = Java.use('android.os.SystemProperties');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    SP.get.overload('java.lang.String').implementation = function(k) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if(k==='ro.build.tags') return 'test-keys';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(k==='ro.debuggable') return '1';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if(k==='ro.secure') return '0';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return this.get(k);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch(e) {}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Hook PackageManager
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            var PM = Java.use('android.content.pm.PackageManager');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                var rootPkgs = ['com.topjohnwu.magisk','eu.chainfire.supersu','com.noshufou.android.su','com.thirdparty.superuser','com.stericson.busybox'];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    PM.getPackageInfo.overload('java.lang.String','int').implementation = function(p,f) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(rootPkgs.indexOf(p)>=0) throw Java.use('android.content.pm.PackageManager$NameNotFoundException').$new(p+" not found");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return this.getPackageInfo(p,f);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // Hook SELinux
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            var SEL = Java.use('android.os.SELinux');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    SEL.isSELinuxEnabled.implementation = function() { return true; };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            SEL.isSELinuxEnforced.implementation = function() { return false; };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch(e) {}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        console.log("[RootSpoofer] All hooks active!");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        JSDEFAULT
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Create Frida config
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cat > "$ASSETS_DIR/frida-gadget.config.json" << 'FCONF'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "interaction": {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "type": "listen",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "address": "127.0.0.1:27042",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "on_port": "reuse"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "scripts": {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "load": ["bypass_root.js"]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        FCONF

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Step 6: Patch smali
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        info "[6/8] Patching smali to auto-load Frida..."

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Find main activity
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        MAIN_CLASS=""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        for file in $(grep -rl "android.intent.action.MAIN" "$WORK_DIR/decompiled" 2>/dev/null); do
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if [[ "$file" == *"AndroidManifest.xml" ]]; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    MAIN_CLASS=$(grep -oP 'android:name="\K[^"]+' "$file" | head -1)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            break
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                fi
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                done

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if [ -n "$MAIN_CLASS" ]; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    SMAIL_PATH="${MAIN_CLASS//./\/}.smali"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        for smali_dir in "$WORK_DIR/decompiled"/smali*; do
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                SMAIL_FILE="$smali_dir/$SMAIL_PATH"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if [ -f "$SMAIL_FILE" ]; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    log "Found main activity smali: $SMAIL_FILE"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                # Add loadLibrary call
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            sed -i 's|invoke-super {p0, p1}, Landroid/app/Activity;->onCreate(Landroid/os/Bundle;)V|invoke-static {}, Lcom/hackerai/rootspoofer/FridaLoader;->load()V\n    invoke-super {p0, p1}, Landroid/app/Activity;->onCreate(Landroid/os/Bundle;)V|g' "$SMAIL_FILE"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        break
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                fi
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    done
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    fi

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    # Create FridaLoader smali
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mkdir -p "$WORK_DIR/decompiled/smali/com/hackerai/rootspoofer"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cat > "$WORK_DIR/decompiled/smali/com/hackerai/rootspoofer/FridaLoader.smali" << 'FSMALI'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .class public Lcom/hackerai/rootspoofer/FridaLoader;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .super Ljava/lang/Object;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .method public static load()V
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .locals 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const-string v0, "frida-gadget"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                invoke-static {v0}, Ljava/lang/System;->loadLibrary(Ljava/lang/String;)V
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return-void
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .end method
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    FSMALI

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    # Step 7: Set debuggable and patch manifest
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    info "[7/8] Setting debuggable flag..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    MANIFEST="$WORK_DIR/decompiled/AndroidManifest.xml"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    sed -i 's|android:debuggable="false"|android:debuggable="true"|g' "$MANIFEST"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    sed -i 's|android:debuggable=[^ ]*|android:debuggable="true"|g' "$MANIFEST"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if ! grep -q "android:debuggable" "$MANIFEST"; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        sed -i 's|<application |<application android:debuggable="true" |g' "$MANIFEST"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fi
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Add debuggable to manifest root too for good measure
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        sed -i 's|<manifest |<manifest android:debuggable="true" |g' "$MANIFEST" 2>/dev/null || true
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        log "Debuggable flag set"

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Step 8: Recompile
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        info "[8/8] Recompiling and signing..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        java -jar "$ROOT_DIR/apktool.jar" b -o "$WORK_DIR/unsigned.apk" "$WORK_DIR/decompiled" || err "Recompile failed"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        log "Recompiled successfully"

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Sign if requested
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if [ "$DO_SIGN" = true ]; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            log "Signing APK..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                java -jar "$ROOT_DIR/uber-apk-signer.jar" --apks "$WORK_DIR/unsigned.apk" --out "$OUTPUT_APK" || {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Fallback: manual sign with keytool
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                KEYSTORE="$ROOT_DIR/pentest.keystore"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        [ ! -f "$KEYSTORE" ] && keytool -genkey -v -keystore "$KEYSTORE" -alias pentest -keyalg RSA -keysize 2048 -validity 365 -storepass pentest123 -keypass pentest123 -dname "CN=RootSpoofer" 2>/dev/null
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                jarsigner -keystore "$KEYSTORE" -storepass pentest123 -keypass pentest123 "$WORK_DIR/unsigned.apk" pentest
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cp "$WORK_DIR/unsigned.apk" "$OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                log "Signed: $OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                else
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cp "$WORK_DIR/unsigned.apk" "$OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        log "Unsigned: $OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fi

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Auto-install if requested
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if [ "$AUTO_INSTALL" = true ]; then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            log "Installing..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                adb install -r "$OUTPUT_APK" 2>/dev/null && log "Installed!" || warn "Install failed (adb not available or device not connected)"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                fi

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                # Cleanup
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                rm -rf "$WORK_DIR"

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo -e "${GREEN}==========================================${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo -e "${GREEN}  SUCCESS!${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo -e "${GREEN}==========================================${NC}"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo "  Patched APK: $OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo "  Size: $(du -h "$OUTPUT_APK" | cut -f1)"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo "  Install: adb install $OUTPUT_APK"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo "  Or copy to device and open"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                echo ""